function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function splitSentences(text) {
  const normalized = normalizeText(text)
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!normalized) return [];

  const matches = normalized.match(/[^.!?…]+[.!?…]+|[^.!?…]+$/g) ?? [];
  const sentences = matches.map((item) => item.trim()).filter(Boolean);
  return sentences.length > 0 ? sentences : [normalized];
}

function buildChunksFromText(text, prefix = 'part_text') {
  const sentences = splitSentences(text);
  if (sentences.length === 0) return [];

  const chunks = [];
  let localIndex = 0;

  for (let cursor = 0; cursor < sentences.length; cursor += 3) {
    localIndex += 1;
    const block = sentences.slice(cursor, cursor + 3);
    const chunkText = block.join(' ').trim();
    if (!chunkText) continue;

    chunks.push({
      chunk_key: prefix + ':' + localIndex,
      partName: prefix,
      index: localIndex,
      text: chunkText,
      sentence_count: block.length,
    });
  }

  return chunks;
}

function normalizeChunkManifest(items) {
  if (!Array.isArray(items)) return [];

  const normalized = [];
  for (const item of items) {
    const text = normalizeText(item?.text);
    if (!text) continue;
    const partName = String(item?.partName ?? item?.part_name ?? 'part_unknown').trim() || 'part_unknown';
    const indexRaw = Number(item?.index ?? item?.order ?? normalized.length + 1);
    const index = Number.isFinite(indexRaw) && indexRaw > 0 ? Math.floor(indexRaw) : (normalized.length + 1);
    const sentenceCountRaw = Number(item?.sentence_count ?? 0);
    const sentenceCount = Number.isFinite(sentenceCountRaw) && sentenceCountRaw > 0
      ? Math.min(3, Math.floor(sentenceCountRaw))
      : Math.min(3, splitSentences(text).length || 1);

    normalized.push({
      chunk_key: String(item?.chunk_key ?? (partName + ':' + index)).trim() || (partName + ':' + index),
      partName,
      index,
      text,
      sentence_count: sentenceCount,
    });
  }

  return normalized;
}

function parseDriveFileIdFromUrl(url) {
  const text = safeText(url);
  if (!text) return '';

  const byPath = text.match(/\/d\/([a-zA-Z0-9_-]{10,})/);
  if (byPath) return String(byPath[1] ?? '').trim();

  const byQuery = text.match(/[?&]id=([a-zA-Z0-9_-]{10,})/);
  if (byQuery) return String(byQuery[1] ?? '').trim();

  const byUc = text.match(/\/uc\?.*?[?&]id=([a-zA-Z0-9_-]{10,})/);
  if (byUc) return String(byUc[1] ?? '').trim();

  return '';
}

function parseDriveFolderIdFromUrl(url) {
  const text = safeText(url);
  if (!text) return '';

  const byPath = text.match(/\/folders\/([a-zA-Z0-9_-]{10,})/);
  if (byPath) return String(byPath[1] ?? '').trim();

  const byQuery = text.match(/[?&]folder=([a-zA-Z0-9_-]{10,})/);
  if (byQuery) return String(byQuery[1] ?? '').trim();

  return '';
}

