function pickFirstString(values) {
  for (const value of values) {
    const text = String(value ?? '').trim();
    if (text) return text;
  }
  return '';
}

function pickResponseSource(value) {
  const candidates = [value, value?.body, value?.data, value?.response, value?.result, value?.output, value?.json];
  for (const candidate of candidates) {
    if (candidate && typeof candidate === 'object') return candidate;
  }
  return value ?? {};
}

function normalizeBaseUrl(baseUrl) {
  return String(baseUrl ?? '').trim().replace(/\/$/, '');
}

function buildStatusUrl(baseUrl, statusPath, jobId) {
  const normalizedBase = normalizeBaseUrl(baseUrl);
  const normalizedPath = String(statusPath ?? '/jobs').trim() || '/jobs';
  const path = normalizedPath.startsWith('/') ? normalizedPath : '/' + normalizedPath;
  const safeJobId = encodeURIComponent(String(jobId ?? '').trim());
  if (!normalizedBase) return '';
  return normalizedBase + path.replace(/\/$/, '') + '/' + safeJobId;
}

const source = pickResponseSource(input);
const errorText = safeText(input.error?.message ?? input.error ?? source.error?.message ?? source.error, '');

const requestId = safeText(
  input.request_id,
  safeText(source.request_id, safeText(source.job_id, safeText(source.id, 'req-' + Date.now().toString(36)))),
);

