  source.data?.videoUrl,
  source.result?.video,
  source.result?.video_url,
  source.result?.videoUrl,
  source.output?.video,
  source.output?.video_url,
  source.output?.videoUrl,
]);

const deadlineMs = Date.parse(input.image_poll_deadline_at ?? '');
const timedOut = Number.isFinite(deadlineMs) ? Date.now() > deadlineMs : false;

const pendingStatuses = ['queued', 'pending', 'processing', 'running', 'in_progress', 'inprogress', 'started', 'submitted', 'working', 'open'];
const doneStatuses = ['done', 'succeeded', 'success', 'completed', 'complete', 'ready', 'finished', 'available', 'delivered'];
const failedStatuses = ['failed', 'error', 'cancelled', 'canceled', 'timeout', 'aborted', 'rejected'];

let pollState = 'pending';
if (timedOut) {
  pollState = 'failed';
} else if (errorText || failedStatuses.includes(statusText)) {
  pollState = 'failed';
} else if (doneStatuses.includes(statusText) || image || video) {
  pollState = 'done';
} else if (pendingStatuses.includes(statusText)) {
  pollState = 'pending';
} else if (progress !== null) {
  pollState = progress >= 100 ? 'done' : 'pending';
} else if (statusText) {
  pollState = 'failed';
} else if (image || video) {
  pollState = 'done';
} else {
  pollState = 'failed';
}

