function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function clampInt(value, fallback = 0, min = 0, max = 1000000) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function normalizeItem(item) {
  return {
    chunk_key: safeText(item.chunk_key),
    partName: safeText(item.partName),
    index: clampInt(item.index, 0, 0, 1000000),
    text: safeText(item.text),
    sentence_count: clampInt(item.sentence_count, 0, 0, 3),
    image: safeText(item.image),
    video: safeText(item.video),
    image_status: safeText(item.image_status, 'unknown'),
    error_reason: item.error_reason ?? null,
  };
}

