  .map(normalizeItem)
  .sort((a, b) => a.index - b.index || a.chunk_key.localeCompare(b.chunk_key));

const first = inputItems[0] ?? {};
const requestId = safeText(first.request_id, 'req-' + Date.now().toString(36));

return [{
  json: {
    ...first,
    workflow: 'text-to-images',
    request_id: requestId,
    media_image_items: sortedItems,
